window.I18N.q.tr.airbrakes = {
  42:{q:"Motor kapalı, frenler bırakılmış, tam dolu kombinasyon araç: gösterge 30 saniyede 3 psi düşüyor. Bu:",options:["İyi — 2 psi sınırının altında","Çok fazla — dakikada 6 psi eder, kombinasyon için 3 psi/dk sınırının üstünde","İyi — kombinasyonlar 4 psi'ye kadar kaybedebilir","Motor çalışmadan değerlendirilemez"],explanation:"30 saniyede 3 psi = dakikada 6 psi — kombinasyonların bırakılmış-fren sınırı olan 3 psi/dk'nın (tek araçlarda 2 psi/dk) çok üstünde. Sürmeden önce düzelt."},
  43:{q:"Hava frenlerinde, algı ve tepkiden sonra pedala basarsın. 55 mil/saatte ~32 fitlik 'fren gecikmesi' şundan kaynaklanır:",options:["Sürücünün yavaş tepki vermesi","Pedala basıldıktan sonra havanın gidip frenleri uygulaması için gereken yaklaşık yarım saniye","ABS'nin frenleri açıp kapaması","Frenlerin aşırı ısınması"],explanation:"Hava frenleri fren gecikmesi ekler — havanın hareket edip uygulaması ~yarım saniye — bu 55 mil/saatte yaklaşık 32 fittir, algı/tepki/frenleme mesafesinin üstüne."},
  44:{q:"Düşük hava uyarısını yok sayıp basınç düşmeye devam ederken sürmeye devam ediyorsun. Yay (acil) frenleri kendiliğinden yaklaşık kaçta devreye girer?",options:["55 psi","tam 45 psi","20 ila 45 psi","0 psi"],explanation:"Hava basıncı 20–45 psi aralığına düşünce yay frenleri otomatik uygulanır — belki güvensiz bir anda. Bu yüzden uyarı gelir gelmez durulur."},
  45:{q:"Hava basıncın 140 psi'yi geçip emniyet valfi 150 psi'de hava boşaltıyor. En olası sorun:",options:["Normal — sistem sadece dolu","Governor kompresörü kesmiyor ve onarım gerekiyor","Çok fazla fren yapıyorsun","Düşük hava uyarısı takılı kalmış"],explanation:"Governor kompresörü ~120–140 psi'de kesmeli. Basınç 150'ye çıkıp emniyet valfi boşaltıyorsa governor arızalıdır — tamir ettir."},
  46:{q:"Sürerken birincil hava devresi aniden arızalanıyor. Düzgün çalışan bir çift sistemde hangisi DOĞRUDUR?",options:["Tüm freni bir anda kaybedersin","İkincil devre seni yine durdurur (daha uzun mesafede) ve düşük hava uyarısı yanar","Yay frenleri her hızda anında kilitlenir","Sadece el freni çalışır"],explanation:"Çift sistemde birincil ve ikincil ayrıdır. Biri arızalanırsa diğeri aracı yine durdurur (daha uzun mesafe) ve düşük hava uyarısı seni uyarır."},
  47:{q:"Bir manuel slack adjuster'ı sertçe çekiyorsun ve yaklaşık 1,5 inç hareket ediyor. Bu şu demektir:",options:["Frenler iyi ayarlı","Frenler ayar dışı (yaklaşık 1 inçten fazla boşluk) ve güvensiz","Fren körüğü çok büyük","ABS sıfırlanmalı"],explanation:"Bir slack adjuster, itme çubuğunun bağlandığı yerde yaklaşık bir inçten fazla hareket ederse frenler ayar dışıdır — en yaygın hava freni kusuru — ve düzeltilmelidir."},
  48:{q:"Uzun bir yokuş indin ve frenler çok sıcak. Hafif eğimde kısa süre park etmen gerekiyor. En doğrusu:",options:["Park (yay) frenlerini sıkıca çekmek","Frenleri soğumaya bırakıp yay frenleri yerine tekerlekleri takozlamak","Motor çalışırken servis frenini basılı tutmak","Sıcak kampanalara su sıkmak"],explanation:"Çok sıcak kampanalara park freni çekmek onlara zarar verebilir, ıslak ve donma varsa donabilir. Soğumaya bırak ve tekerlekleri takozla."},
  49:{q:"Çift hava sisteminde, çalışma devrinde basınç-yükselme kontrolü, basıncın 85'ten 100 psi'ye kaç sürede çıkmasını bekler?",options:["45 saniye","3 dakika","10 saniye","2 dakika"],explanation:"Çift hava sisteminde basınç, motorun çalışma devrinde 45 saniye içinde 85'ten 100 psi'ye yükselmeli; daha yavaşsa sistem talebe yetişemeyebilir."},
  50:{q:"Texas handbook'una göre, düşük hava uyarısı tank basıncı kaçın altına düşmeden önce yanmalıdır?",options:["45 psi","55 psi","60 psi","80 psi"],explanation:"Düşük hava uyarısı, basınç 60 psi'nin altına düşmeden önce devreye girmeli ki hâlâ fren havan varken durabilesin."},
  51:{q:"Yokuşun yarısında pedal yumuşuyor ve fren yaptığın hâlde araç hızlanıyor. Bu büyük olasılıkla:",options:["Servis hattında hava kaçağı","Aşırı ısınmadan fren fade — vites küçült, motor freni kullan, gerekirse kaçış rampası","ABS devreye giriyor","Su birikintisinden ıslak frenler"],explanation:"Yumuşak pedal ve yokuşta artan hız, ısıdan fren fade'e işaret eder. Daha düşük vitese geç, motor freni kullan ve kontrol edemiyorsan kaçış rampası kullan."},
  52:{q:"Servis frenlerini test etmek için:",options:["Otoyol hızından sert fren yap","Yaklaşık 5 mil/saatte ilerle, frene sıkıca bas ve hızlı, düz bir duruş kontrol et","Sadece el frenini çekip bırak","Pedalı hızlıca on kez pompala"],explanation:"Yaklaşık 5 mil/saatte frene sıkıca bas; araç bir yana çekmeden veya süngerimsi hissetmeden hemen durmalı."},
  53:{q:"Çalıştırmadan sonra çekicinin sarı ABS arıza lambası yanık kalıyor. Yapman gereken:",options:["Hemen dur — frenin gitti","Sürmeye devam et (normal frenin var), dikkatli fren yap ve ABS'yi yakında tamir ettir","Telafi için frenleri sürekli pompala","Sıfırlamak için el frenini bırak"],explanation:"ABS lambası yanık kalırsa sadece antiblokaj işlevini kaybetmişsindir; normal servis frenleri çalışır. Kilitlenmeyi önleyecek şekilde dikkatli sür ve tamir ettir."}
};
window.I18N.q.tr.combination = {
  38:{q:"Sürerken kırmızı trailer-air-supply düğmesi kendiliğinden dışarı fırlıyor. En olası neden:",options:["Otoyol hızında normal davranış","Büyük bir hava kaçağı/kaybı basıncı 20–45 psi aralığına düşürdü","Yanlışlıkla bastın","Römork tam dolu"],explanation:"Düğme (ve tractor protection valf), basınç ~20–45 psi'ye düşünce dışarı fırlar ve römork acil frenlerini uygular. Ciddi hava kaybını gösterir — güvenle dur."},
  39:{q:"Uzun römorkla dar bir sağ dönüş yaparken doğru teknik:",options:["Önce SOLA geniş kır, sonra sağa dön","Çekiciyi yeterince dışarıda tut ve dönüşü TAMAMLARKEN geniş dön, arkayı kaldırıma yakın tut","Direksiyonu olabildiğince erken sert kır","Virajda hızlan"],explanation:"Römork iz saptığı (köşeyi kestiği) için dönüşü bitirirken geniş dön — asla önce sola kırma, bu birinin sağından geçmesine yol açar."},
  40:{q:"Bir tamirci yanlışlıkla servis ve acil glad-hand bağlantılarını çaprazlıyor. Tehlike şudur:",options:["Römork frenleri tüm yol sürter","Pedala bastığında römork frenin olmayabilir","Römork lambaları yanmaz","Hiçbir şey — birbirinin yerine geçer"],explanation:"Çaprazlanan glad hand'ler havayı yanlış hatta gönderir, ihtiyaç anında römork servis frenin olmayabilir. Doğru bağla (mavi=servis, kırmızı=acil) ve sürmeden test et."},
  41:{q:"Hangisinin devrilme olasılığı EN YÜKSEKTİR?",options:["Düz, kuru otoyolda boş römork","Tam yüklü römorkun, tabela hızını 5 mil/saat aşarak çıkış rampasına girmesi","Düşük hızda bobtail çekici","Kuru zeminde düz giden yüklü römork"],explanation:"Devrilmeler çoğunlukla virajdaki hız ve yüksek/dolu ağırlık merkezinden olur. Rampa hızını aşan yüklü rig klasik devrilme senaryosudur."},
  42:{q:"Bağlamadan sonra römork apronu ile beşinci teker arasında gün ışığı (boşluk) görüyorsun. Yapman gereken:",options:["Yavaş sür ve izlemeye devam et","Sürme — kingpin çenelere kilitlenmemiş olabilir ve römork kopabilir","Boşluğu kapatmak için gres ekle","Yok say; küçük boşluk normaldir"],explanation:"Üst ve alt beşinci teker arasında boşluk olmamalı. Boşluk, kingpin'in kilitlenmemiş olabileceğini gösterir — düzelene dek sürme."},
  43:{q:"Beşinci tekerin kingpin'e gerçekten kilitlendiğini doğrulamanın en iyi yolu:",options:["Römork lambalarının çalıştığını kontrol etmek","Römork frenlerini kilitleyip düşük viste hafifçe öne çekmek, sonra inip bağlantıyı incelemek","Römorkun yanına vurmak","Bağlarken bir 'klik' sesi dinlemek"],explanation:"Tug testi yap — römork frenleri kilitliyken hafifçe öne çek; römork bağlı kalmalı. Sonra çenelerin kingpin etrafında kapalı ve boşluksuz olduğunu gözle doğrula."},
  44:{q:"Yüklü bir çekici-römorka kıyasla bobtail çekici (römorksuz) genellikle:",options:["Çok daha kısa mesafede durur","Çekiş tekerleklerinde az ağırlık olduğundan ve kilitlenebileceğinden şaşırtıcı derecede zor durur","Hiç kayamaz","Her konfigürasyonun en iyi frenine sahiptir"],explanation:"Çekiş aksında yük olmayınca tutuş zayıftır, tekerlekler kilitlenip kayabilir, bu yüzden bobtail daha uzun durabilir. Erken ve yumuşak fren yap."},
  45:{q:"Çekici ile römork arasındaki acil (besleme) hattı ne yapar?",options:["Sadece pedal sinyalini taşır","Römork hava tanklarını doldurur ve basıncı kaybolursa römork acil frenlerini uygular","Römork işaret lambalarını besler","Sürerken hiçbir şey"],explanation:"Acil/besleme hattı römork tanklarını doldurur; basıncının kaybı (örn. kopma) römork acil frenlerini uygular. Servis hattı pedal sinyalini taşır."},
  46:{q:"Römorku geri alırken römorkun arkasının SAĞA gitmesini istiyorsun. Direksiyonu önce şöyle çevirirsin:",options:["Sağa","Sola, sonra römorku takip ederek geri çevir","Düz, sonra fren","Geri viteste römork yönlendirilemez"],explanation:"Römork geri alma otomobilin tersidir: römorku sağa göndermek için direksiyonu önce sola çevir, sonra takip etmek için geri çevir. Yavaş ve yardımcıyla geri al."},
  47:{q:"Çok ÖNE kilitlenmiş kayar bir beşinci teker şuna yol açabilir:",options:["Konfor artışı","Direksiyon aksına çok fazla ağırlık bindirip dönüşlerde kabin-römork açıklığını azaltır","Direksiyon aksından ağırlık alır","Hiçbir şeye etkisi olmaz"],explanation:"Beşinci tekerin konumu ağırlığı akslar arasında kaydırır ve dönüş açıklığını değiştirir. Çok öne, direksiyon aksını aşırı yükler ve dönüşlerde römorku kabine yaklaştırır."},
  48:{q:"Yolda yavaşlamak için trailer hand valve'i (trolley / Johnson bar) kullanmak tehlikelidir çünkü:",options:["Sadece römorku frenler ve römork kaymasına yol açabilir","Sadece çekiciyi frenler","Park frenlerini bırakır","Çok yakıt harcar"],explanation:"Hand valve sadece römork frenlerini uygular; yavaşlamak için kullanmak römorku kaydırabilir. Onu yalnızca römork frenlerini test etmek için kullan — durmak için ayak frenini kullan."},
  49:{q:"Römork BOŞKEN ani, sert şerit değişimi neden özellikle tehlikelidir?",options:["Boş römorklar yola daha iyi tutunur","Hafif arka kısım büyür ve savrulup devrilebilir ('crack the whip')","Zaten zaman kazandırmaz","Boş römorkla hiçbir şey olmaz"],explanation:"Ani direksiyon hareketi kombinasyonun arkasında büyür; boş, tepesi ağır römork savrulup devrilebilir. Yumuşak ve erken yönlendir."}
};

/* ===== RU — new HARD questions ===== */
Object.assign(window.I18N.q.ru.special, {
  43:{q:"Груз днём выступает на 5 футов за задний край ТС. Чем нужно отметить конец?",options:["Красным флажком не менее 12 дюймов по стороне","Белым флажком 12 дюймов по стороне","Красным фонарём, видимым с 500 футов","Ничем — отметка нужна только свыше 6 футов"],explanation:"Свыше 4 футов заднего выступа днём нужен красный флажок (не менее 12×12 дюймов). Белые флажки — для буксировки; красный фонарь — ночное требование; порог 4 фута, не 6."},
  44:{q:"Вы буксируете сломанный автомобиль стальной цепью. Что Техас требует прикрепить к цепи?",options:["Красный флажок 12×12 дюймов","Белый флажок или ткань не менее 12×12 дюймов","Оранжевый треугольник","Горящий красный фонарь"],explanation:"К цепи/тросу/канату для буксировки крепят белый флажок/ткань не менее 12×12 дюймов. Красный флажок — для выступающего груза, а не для сцепки."},
  45:{q:"На грузовике шириной 84 дюйма что из следующего НЕВЕРНО?",options:["Жёлтые габаритные фонари спереди","Красные габаритные фонари сзади","Два красных отражателя сзади на высоте 24–60 дюймов","Жёлтые габаритные фонари сзади"],explanation:"Задние фонари и отражатели — КРАСНЫЕ, не жёлтые; жёлтый — спереди. Поэтому 'жёлтые габаритные фонари сзади' — неверно."},
  46:{q:"Какая пара диапазонов высоты установки верна?",options:["Фары 24–54 дюйма; задние отражатели 24–60 дюймов","Фары 24–60 дюймов; задние отражатели 24–54 дюйма","Фары 12–48 дюймов; задние отражатели 24–60 дюймов","Оба 24–54 дюйма"],explanation:"Белые фары — 24–54 дюйма; задние красные отражатели — 24–60 дюймов. Не путай диапазоны."},
  47:{q:"Вне делового/жилого района грузовик не может следовать за другим грузовиком ближе 300 футов. Это правило:",options:["Полностью запрещает обгон одного грузовика другим","НЕ запрещает обгон и опережение","Действует только после темноты","Действует только в черте города"],explanation:"Грузовики должны оставлять 300 футов между собой на открытой дороге, чтобы другие могли безопасно обгонять; но правило не запрещает обгон."},
  48:{q:"Состав ТС массой 3 500 фунтов должен останавливаться с 20 миль/ч в пределах:",options:["40 футов","50 футов","30 футов","60 футов"],explanation:"Свыше 3 000 фунтов лимит — 50 футов с 20 миль/ч; до 3 000 фунтов — 40 футов. 3 500 фунтов больше 3 000, значит 50 футов."},
  49:{q:"Без разрешения какое ТС с грузом укладывается И в ширину, И в высоту Техаса?",options:["102 дюйма в ширину и 14 футов в высоту","108 дюймов в ширину и 14 футов в высоту","102 дюйма в ширину и 14 футов 6 дюймов в высоту","96 дюймов в ширину и 15 футов в высоту"],explanation:"Максимум ширины — 102 дюйма, высоты — 14 футов. Только первый вариант проходит по обоим; остальные превышают ширину или высоту."},
  50:{q:"Брызговики обязательны на грузовиках/прицепах, у которых на задней оси ____, и должны доходить до ____ от дороги.",options:["четыре и более шин; 8 дюймов","две и более шин; 6 дюймов","любое число шин; 12 дюймов","четыре и более шин; 4 дюйма"],explanation:"ТС с четырьмя и более шинами на задней оси нужны брызговики до 8 дюймов от дороги (прицепы-штанги и бобтейлы — исключение)."},
  51:{q:"После трудоустройства в Техасе номера другого штата признаются 30 дней. А временный картонный номер покупателя действует:",options:["30 дней","20 дней","60 дней","90 дней"],explanation:"Номера другого штата: 30 дней после резидентства/работы. Временный картонный номер покупателя: только 20 дней. Не путай две цифры."},
  52:{q:"Что из следующего ЗАКОННО / разрешено в Техасе?",options:["Катиться под уклон на нейтрали","Грузовик с плакатами опасного груза проезжает свободный переезд без остановки","Показывать красный свет вперёд","Накрыть груз гравия, чтобы он не разлетался"],explanation:"Накрывать сыпучий груз обязательно и законно. Накат на нейтрали, проезд опасного груза без остановки и красный свет вперёд запрещены."},
  53:{q:"Задние фонари должны быть видны ____ сзади; стоп-сигналы днём — с ____.",options:["1 000 футов; 300 футов","500 футов; 1 000 футов","300 футов; 1 000 футов","1 000 футов; 500 футов"],explanation:"Задние фонари (красные) видны с 1 000 футов сзади; стоп-сигналы при дневном свете — с 300 футов. Не путай цифры."},
  54:{q:"Грузовик длиной 30 футов, но шириной всего 70 дюймов, сломался на обочине. Нужно ли включать аварийку?",options:["Нет — ширина меньше 80 дюймов","Да — длина 30 футов и более включает требование при остановке на проезжей части или обочине","Только если стемнело","Только в черте города"],explanation:"Правило действует для ТС шириной 80 дюймов и более ИЛИ длиной 30 футов и более. При длине 30 футов оно применяется — аварийка обязательна при остановке на дороге/обочине (кроме законной парковки/погрузки в городе)."}
});
window.I18N.q.ru.general = {
  70:{q:"На 55 миль/ч появляется опасность. Ещё до того как нога коснётся тормоза, восприятие (~1,5 с) и реакция (~0,75 с) уже прошли. Сколько примерно проехало ТС к этому моменту?",options:["Около 60 футов","Около 142 футов","Около 200 футов","Около 419 футов"],explanation:"Дистанция восприятия ~142 фута + дистанция реакции ~61 фут ≈ около 200 футов до начала торможения. Торможение затем добавляет ~216 футов, итого ~419 футов."},
  71:{q:"При одной и той же скорости какая ситуация даёт САМЫЙ длинный тормозной путь?",options:["Полностью гружёный грузовик на сухом покрытии","Пустой грузовик на мокрой дороге","Гружёный грузовик на влажной дороге","Пустой грузовик на сухом покрытии"],explanation:"У пустых грузовиков плохое сцепление (тормоза/шины рассчитаны на гружёную массу), а мокрая дорога снижает его ещё больше — худшее сочетание, колёса склонны блокироваться."},
  72:{q:"Вы тянете 70-футовый состав на 62 миль/ч в ясную погоду. Рекомендуемая дистанция следования примерно:",options:["6 секунд","7 секунд","8 секунд","10 секунд"],explanation:"Одна секунда на каждые 10 футов длины = 7 секунд для 70 футов; свыше 40 миль/ч добавь секунду — получится 8 секунд."},
  73:{q:"В сильный дождь на 35 миль/ч руль вдруг становится лёгким и ТС не реагирует. ПЕРВОЕ действие:",options:["Сильно затормозить","Убрать ногу с газа и выжать сцепление","Резко рулить в поисках сцепления","Резко понизить передачу"],explanation:"Это аквапланирование. Отпусти газ и выжми сцепление, чтобы колёса замедлились и вновь схватили дорогу; не тормози резко и не рули резко."},
  74:{q:"Что из утверждений об ABS ВЕРНО?",options:["ABS всегда сокращает тормозной путь","ABS позволяет рулить, не давая колёсам блокироваться, но не обязательно тормозит короче","Если лампа ABS горит — тормозов нет совсем","ABS значит, что при резком торможении надо качать педаль"],explanation:"ABS не даёт колёсам блокироваться, позволяя рулить при сильном торможении. Путь не обязательно короче, при горящей лампе обычные тормоза работают, а педаль надо держать, а не качать."},
  75:{q:"На длинном крутом спуске скорость нужно контролировать ГЛАВНЫМ образом:",options:["Постоянным лёгким нажатием тормоза всю дорогу","Низкой передачей и двигателем, с редким уверенным (snub) торможением","Стояночным тормозом","Накатом на нейтрали ради экономии тормозов"],explanation:"До спуска будь на низкой передаче, чтобы двигатель держал скорость; используй короткое уверенное snub-торможение лишь как дополнение. Постоянное торможение перегревает тормоза (fade)."},
  76:{q:"В 01:00 машина впереди дрейфует в полосе, без причины замедляется, затем ускоряется. САМАЯ вероятная опасность:",options:["Заблудившийся турист","Пьяный или сонный водитель","Мелкая неисправность","Кто-то на круиз-контроле"],explanation:"Дрейф плюс рваная скорость глубокой ночью сильнее всего указывают на пьяного/сонного водителя. Держи большую дистанцию и не обгоняй вплотную."},
  77:{q:"Вы везёте одну стальную балку длиной 23 фута. Не считая правило по весу, минимум креплений по правилу длины:",options:["Два","Три","Четыре","Одно"],explanation:"Минимум одно крепление на каждые 10 футов груза: для 23 футов нужно три (покрывает до 30 футов), и никогда меньше двух. Значит три."},
  78:{q:"На съезде указано 35 миль/ч. Вы ведёте полупустую цистерну. Съезд надо проходить:",options:["Ровно 35 миль/ч — знак для грузовиков","Чуть ниже 35","Намного ниже 35 из-за высокого центра тяжести и плеска жидкости","На любой скорости, если есть перегородки"],explanation:"Знаки скорости — для легковых в хороших условиях. Цистерна с высоким центром тяжести и плещущейся жидкостью может опрокинуться на знаковой скорости — иди намного ниже, даже с перегородками."},
  79:{q:"На проверке у водителя CMV прибор показывает 0,02% BAC. Что будет?",options:["Ничего — это ниже предела 0,04%","Выведен из эксплуатации на 24 часа","Немедленная дисквалификация на год","Обвинение в DUI на месте"],explanation:"Любой обнаруживаемый алкоголь ниже 0,04% означает вывод из эксплуатации на 24 часа. При 0,04% и выше — это DUI / дисквалифицирующее нарушение."},
  80:{q:"Шина прицепа загорелась из-за перегретого подшипника. Что верно?",options:["Никогда не лей воду ни на какой пожар ТС","Воду можно использовать для охлаждения горящей шины, но при электрическом/топливном пожаре — огнетушитель B:C","Только вода, никогда огнетушитель","Огнетушитель класса A на топливный бак"],explanation:"Вода может охладить горящую шину (и подходит для дерева/бумаги/ткани), но никогда не лей воду на электрический или бензиновый пожар — там нужен огнетушитель B:C."},
  81:{q:"На тёмной дороге ближний свет освещает около 250 футов. Чтобы не 'перегонять' фары, скорость должна быть не более примерно:",options:["30 миль/ч","40 миль/ч","55 миль/ч","65 миль/ч"],explanation:"Надо успевать остановиться в пределах видимости. Полный тормозной путь достигает ~250 футов примерно на 40 миль/ч; быстрее — не остановишься в зоне света фар."}
};
window.I18N.q.ru.airbrakes = {
  42:{q:"Двигатель выключен, тормоза отпущены, состав полностью заряжен: манометр падает на 3 psi за 30 секунд. Это:",options:["Нормально — ниже предела 2 psi","Слишком много — это 6 psi в минуту, выше предела 3 psi/мин для состава","Нормально — составы могут терять до 4 psi","Нельзя оценить без работающего двигателя"],explanation:"3 psi за 30 секунд = 6 psi в минуту — намного выше предела для составов 3 psi/мин (2 psi/мин для одиночных) при отпущенных тормозах. Устрани до выезда."},
  43:{q:"У пневмотормозов после восприятия и реакции вы жмёте педаль. Дополнительные ~32 фута 'задержки тормозов' на 55 миль/ч возникают из-за:",options:["Медленной реакции водителя","Примерно полусекунды, нужной воздуху чтобы дойти и сработать после нажатия педали","Срабатывания ABS","Перегрева тормозов"],explanation:"Пневмотормоза добавляют задержку — около полусекунды на ход воздуха и срабатывание — это примерно 32 фута на 55 миль/ч, сверх дистанции восприятия, реакции и торможения."},
  44:{q:"Вы игнорируете предупреждение о низком давлении и едете, пока давление падает. Пружинные (аварийные) тормоза сработают сами примерно при:",options:["55 psi","ровно 45 psi","20–45 psi","0 psi"],explanation:"Когда давление падает в диапазон 20–45 psi, пружинные тормоза срабатывают автоматически — возможно, в опасный момент. Поэтому останавливайся, как только загорелось предупреждение."},
  45:{q:"Давление поднимается выше 140 psi, и предохранительный клапан стравливает воздух при 150 psi. Наиболее вероятная проблема:",options:["Нормально — система просто полна","Регулятор (governor) не отключает компрессор и требует ремонта","Вы слишком много тормозите","Предупреждение о низком давлении залипло"],explanation:"Регулятор должен отключать компрессор около 120–140 psi. Если давление доходит до 150 и клапан стравливает, регулятор неисправен — почини."},
  46:{q:"Во время движения внезапно отказывает первичный контур. Что ВЕРНО для исправной двойной системы?",options:["Вы теряете всё торможение сразу","Вторичный контур всё ещё останавливает ТС (с большей дистанцией), и загорается предупреждение","Пружинные тормоза мгновенно блокируются на любой скорости","Работает только стояночный тормоз"],explanation:"В двойной системе первичный и вторичный раздельны. Если один откажет, другой всё равно тормозит (большая дистанция), а предупреждение оповестит."},
  47:{q:"Вы сильно тянете ручной регулятор зазора (slack adjuster), и он сдвигается примерно на 1,5 дюйма. Это значит:",options:["Тормоза хорошо отрегулированы","Тормоза разрегулированы (более ~1 дюйма свободного хода) и небезопасны","Тормозная камера слишком велика","Нужно сбросить ABS"],explanation:"Если регулятор сдвигается более чем на дюйм в месте крепления штока, тормоза разрегулированы — самый частый дефект пневмотормозов — и требуют регулировки."},
  48:{q:"Вы только что спустились с длинного уклона, тормоза очень горячие. Нужно ненадолго припарковаться на лёгком склоне. Лучшее:",options:["Затянуть стояночные (пружинные) тормоза","Дать тормозам остыть и подложить упоры под колёса вместо стояночного тормоза","Держать рабочий тормоз при работающем двигателе","Полить горячие барабаны водой"],explanation:"Стояночный тормоз на очень горячих барабанах может их повредить, а в мороз и сырость — примёрзнуть. Дай остыть и подложи упоры."},
  49:{q:"В двойной пневмосистеме на рабочих оборотах проверка нарастания давления ожидает рост с 85 до 100 psi за:",options:["45 секунд","3 минуты","10 секунд","2 минуты"],explanation:"В двойной системе давление должно расти с 85 до 100 psi за 45 секунд на рабочих оборотах двигателя; медленнее — система может не успевать."},
  50:{q:"По справочнику Техаса предупреждение о низком давлении должно загораться до того, как давление в баках упадёт ниже:",options:["45 psi","55 psi","60 psi","80 psi"],explanation:"Предупреждение должно срабатывать до падения ниже 60 psi, чтобы успеть остановиться, пока ещё есть воздух для торможения."},
  51:{q:"На середине спуска педаль становится мягче, и ТС ускоряется, хотя вы тормозите. Скорее всего это:",options:["Утечка воздуха в рабочей магистрали","Угасание тормозов (fade) от перегрева — понизь передачу, тормози двигателем, при необходимости аварийный съезд","Срабатывание ABS","Мокрые тормоза после лужи"],explanation:"Мягкая педаль и рост скорости на спуске указывают на угасание тормозов от тепла. Перейди на низшую передачу, тормози двигателем и используй аварийный съезд, если не справляешься."},
  52:{q:"Чтобы проверить рабочие тормоза, нужно:",options:["Резко затормозить с трассовой скорости","Прокатиться на ~5 миль/ч, уверенно нажать тормоз и проверить быстрый, прямой останов","Только затянуть и отпустить стояночный тормоз","Быстро качнуть педаль десять раз"],explanation:"На ~5 миль/ч уверенно нажми тормоз; ТС должно сразу остановиться без увода в сторону и без 'губчатости'."},
  53:{q:"После запуска жёлтая лампа неисправности ABS на тягаче не гаснет. Нужно:",options:["Немедленно остановиться — тормозов нет","Продолжать ехать (обычные тормоза есть), тормозить аккуратно и вскоре починить ABS","Постоянно качать тормоз для компенсации","Отпустить стояночный тормоз, чтобы сбросить"],explanation:"Если лампа ABS горит, потеряна только антиблокировка; обычные рабочие тормоза работают. Веди аккуратно, избегая блокировки, и почини."}
};
window.I18N.q.ru.combination = {
  38:{q:"Во время движения красная кнопка подачи воздуха в прицеп сама выскакивает. Наиболее вероятная причина:",options:["Нормальное поведение на трассе","Крупная утечка/потеря воздуха уронила давление в диапазон 20–45 psi","Вы случайно нажали её","Прицеп полностью гружён"],explanation:"Кнопка (и tractor protection valve) выскакивает, когда давление падает до ~20–45 psi, применяя аварийные тормоза прицепа. Это сигнал серьёзной потери воздуха — безопасно остановись."},
  39:{q:"Делая крутой правый поворот с длинным прицепом, правильная техника:",options:["Сначала вильнуть ВЛЕВО, затем повернуть","Держать тягач достаточно снаружи и поворачивать широко, ЗАВЕРШАЯ поворот, держа зад у бордюра","Повернуть руль как можно раньше и резко","Ускориться в повороте"],explanation:"Из-за смещения траектории (срезания угла) поворачивай широко, завершая поворот — никогда не виляй сначала влево, это провоцирует обгон справа."},
  40:{q:"Механик случайно перекрестил соединения рабочей и аварийной магистралей (glad hands). Опасность в том, что:",options:["Тормоза прицепа будут подтормаживать всю дорогу","У вас может не быть тормозов прицепа, когда вы нажмёте педаль","Не будут гореть фонари прицепа","Ничего — они взаимозаменяемы"],explanation:"Перекрещенные glad hands подают воздух не в ту магистраль, и рабочих тормозов прицепа может не быть в нужный момент. Соединяй правильно (синий=рабочая, красный=аварийная) и проверяй до выезда."},
  41:{q:"Что СКОРЕЕ всего опрокинется?",options:["Пустой прицеп на прямой сухой трассе","Полностью гружёный прицеп на съезде на 5 миль/ч выше знака","Бобтейл-тягач на малой скорости","Гружёный прицеп прямо по сухому покрытию"],explanation:"Опрокидывания в основном от скорости в повороте и высокого/гружёного центра тяжести. Гружёный состав выше скорости съезда — классический сценарий опрокидывания."},
  42:{q:"После сцепки вы видите дневной свет (зазор) между фартуком прицепа и седлом. Нужно:",options:["Ехать медленно и наблюдать","Не ехать — шкворень может быть не заперт в захватах, и прицеп может оторваться","Добавить смазки, чтобы закрыть зазор","Игнорировать; небольшой зазор нормален"],explanation:"Между верхним и нижним седлом не должно быть зазора. Зазор означает, что шкворень может быть не заперт — не едь, пока не исправишь."},
  43:{q:"Лучший способ убедиться, что седло действительно заперто на шкворне:",options:["Проверить, что работают фонари прицепа","Заблокировать тормоза прицепа и мягко потянуть вперёд на низшей передаче, затем выйти и осмотреть сцепку","Постучать по борту прицепа","Слушать 'щелчок' при сцепке"],explanation:"Сделай tug-тест — при заблокированных тормозах прицепа мягко потяни вперёд; прицеп должен остаться сцепленным. Затем визуально убедись, что захваты сомкнуты вокруг шкворня без зазора."},
  44:{q:"По сравнению с гружёным тягачом с прицепом, бобтейл-тягач (без прицепа) обычно:",options:["Останавливается намного короче","Может неожиданно тяжело тормозить, ведь на ведущих колёсах мало веса и они блокируются","Вообще не может скользить","Имеет лучшее торможение из всех конфигураций"],explanation:"Без нагрузки на ведущую ось сцепление плохое, колёса блокируются и скользят, поэтому бобтейлу может потребоваться больший путь. Тормози рано и мягко."},
  45:{q:"Аварийная (питающая) магистраль между тягачом и прицепом делает что?",options:["Передаёт только сигнал педали","Заряжает баки прицепа и применяет аварийные тормоза прицепа при потере её давления","Питает габаритные фонари прицепа","Ничего во время движения"],explanation:"Аварийная/питающая магистраль заряжает баки прицепа; потеря её давления (например, отрыв) применяет аварийные тормоза прицепа. Рабочая магистраль передаёт сигнал педали."},
  46:{q:"Сдавая прицеп назад, вы хотите, чтобы зад прицепа пошёл ВПРАВО. Руль сначала поворачиваете:",options:["Вправо","Влево, затем следуете за прицепом, поворачивая обратно","Прямо, затем тормоз","Прицеп нельзя направлять задним ходом"],explanation:"Сдача прицепа противоположна легковой: чтобы прицеп пошёл вправо, сначала поверни руль влево, потом доверни, следуя за ним. Сдавай медленно и с помощником."},
  47:{q:"Скользящее седло, запертое слишком ВПЕРЁД, может:",options:["Улучшить плавность хода","Дать слишком много веса на рулевую ось и уменьшить зазор кабина–прицеп в поворотах","Снять вес с рулевой оси","Ни на что не влиять"],explanation:"Положение седла перераспределяет вес между осями и меняет зазор в поворотах. Слишком вперёд — перегружает рулевую ось и приближает прицеп к кабине в поворотах."},
  48:{q:"Использовать ручной кран прицепа (trolley / Johnson bar) для замедления на дороге опасно, потому что:",options:["Он тормозит только прицеп и может вызвать занос прицепа","Он тормозит только тягач","Он отпускает стояночные тормоза","Он расходует много топлива"],explanation:"Ручной кран применяет только тормоза прицепа; торможение им может вызвать занос прицепа. Используй его только для проверки тормозов прицепа — для остановки используй ножной тормоз."},
  49:{q:"Почему резкая смена полосы особенно опасна, когда прицеп ПУСТОЙ?",options:["Пустые прицепы лучше держат дорогу","Лёгкий зад усиливается и может вильнуть и опрокинуться ('crack the whip')","Это всё равно не экономит время","С пустым прицепом ничего не происходит"],explanation:"Резкое движение рулём усиливается в хвосте состава; пустой, верхне-тяжёлый прицеп может вильнуть и опрокинуться. Рули плавно и заранее."}
};
